"use strict";(self.webpackChunkauctions_for_woocommerce_doc=self.webpackChunkauctions_for_woocommerce_doc||[]).push([[3420],{4901(t,e,n){n.r(e),n.d(e,{comp:()=>d,data:()=>o});var s=n(641);const a={},d=(0,n(6262).A)(a,[["render",function(t,e){return(0,s.uX)(),(0,s.CE)("div",null,[...e[0]||(e[0]=[(0,s.Fv)('<h1 id="shortcodes" tabindex="-1"><a class="header-anchor" href="#shortcodes"><span>Shortcodes</span></a></h1><p>For each Gutenberg block / Elementor widget, an equivalent shortcode is available — useful for classic editor, Beaver Builder, Divi, and similar.</p><p><img src="/auctions-for-woocommerce/images/screenshots/front-auction-grid.png" alt="Auction Grid page — what  renders on the storefront when you drop it on any page or template"></p><h2 id="quick-reference" tabindex="-1"><a class="header-anchor" href="#quick-reference"><span>Quick reference</span></a></h2><table><thead><tr><th>Shortcode</th><th>Equivalent</th></tr></thead><tbody><tr><td><code>[wkafw_auctions]</code></td><td>Auction list grid</td></tr><tr><td><code>[wkafw_auction]</code></td><td>Single auction (by ID)</td></tr><tr><td><code>[wkafw_countdown]</code></td><td>Standalone countdown</td></tr><tr><td><code>[wkafw_bid_form]</code></td><td>Bid form (use inside custom layouts)</td></tr><tr><td><code>[wkafw_search]</code></td><td>Search bar</td></tr><tr><td><code>[wkafw_top_bidders]</code></td><td>Leaderboard</td></tr><tr><td><code>[wkafw_recent_winners]</code></td><td>Recently-paid lots</td></tr><tr><td><code>[wkafw_my_auctions]</code></td><td>Customer&#39;s My Auctions tabs</td></tr><tr><td><code>[wkafw_my_wallet]</code></td><td>Wallet balance display</td></tr><tr><td><code>[wkafw_watchlist]</code></td><td>User&#39;s watchlist</td></tr><tr><td><code>[wkafw_auction_of_day]</code></td><td>Featured rotation</td></tr><tr><td><code>[wkafw_flash_auctions]</code></td><td>Flash auction grid</td></tr><tr><td><code>[wkafw_event_landing]</code></td><td>Event page (by event ID)</td></tr><tr><td><code>[wkafw_donor_wall]</code></td><td>Charity donor wall</td></tr><tr><td><code>[wkafw_leaderboard]</code></td><td>Achievements leaderboard</td></tr><tr><td><code>[wkafw_compare]</code></td><td>Comparison page</td></tr><tr><td><code>[wkafw_share_buttons]</code></td><td>Social share row</td></tr><tr><td><code>[wkafw_seller_register]</code></td><td>(legacy) seller registration form</td></tr></tbody></table><h2 id="auction-list-grid" tabindex="-1"><a class="header-anchor" href="#auction-list-grid"><span>Auction list grid</span></a></h2><div class="language-text line-numbers-mode" data-highlighter="prismjs" data-ext="text"><pre><code><span class="line">[wkafw_auctions</span>\n<span class="line">    status=&quot;active&quot;</span>\n<span class="line">    type=&quot;all&quot;</span>\n<span class="line">    category=&quot;watches&quot;</span>\n<span class="line">    sort=&quot;end_date&quot;</span>\n<span class="line">    order=&quot;ASC&quot;</span>\n<span class="line">    limit=&quot;12&quot;</span>\n<span class="line">    columns=&quot;3&quot;</span>\n<span class="line">    layout=&quot;grid&quot;</span>\n<span class="line">    show_countdown=&quot;yes&quot;</span>\n<span class="line">    show_bid_count=&quot;yes&quot;</span>\n<span class="line">    pagination=&quot;yes&quot;</span>\n<span class="line">]</span>\n<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><table><thead><tr><th>Param</th><th>Default</th><th>Values</th></tr></thead><tbody><tr><td><code>status</code></td><td>active</td><td>active, scheduled, ended, paid, all</td></tr><tr><td><code>type</code></td><td>all</td><td>standard, reverse, sealed, proxy, silent, charity, penny, dutch, seated, unique-bid, all</td></tr><tr><td><code>category</code></td><td>(none)</td><td>WC product category slug</td></tr><tr><td><code>vendor_id</code></td><td>(none)</td><td>Filter to one vendor</td></tr><tr><td><code>sort</code></td><td>end_date</td><td>start_date, end_date, current_price, bid_count, created_at</td></tr><tr><td><code>order</code></td><td>ASC</td><td>ASC, DESC</td></tr><tr><td><code>limit</code></td><td>12</td><td>Max items</td></tr><tr><td><code>columns</code></td><td>3</td><td>1–6</td></tr><tr><td><code>layout</code></td><td>grid</td><td>grid, list, carousel</td></tr><tr><td><code>show_countdown</code></td><td>yes</td><td>yes, no</td></tr><tr><td><code>show_bid_count</code></td><td>yes</td><td>yes, no</td></tr><tr><td><code>show_watchers</code></td><td>no</td><td>yes, no</td></tr><tr><td><code>pagination</code></td><td>yes</td><td>yes, no</td></tr><tr><td><code>class</code></td><td>(empty)</td><td>Extra CSS class</td></tr></tbody></table><h2 id="single-auction" tabindex="-1"><a class="header-anchor" href="#single-auction"><span>Single auction</span></a></h2><div class="language-text line-numbers-mode" data-highlighter="prismjs" data-ext="text"><pre><code><span class="line">[wkafw_auction id=&quot;123&quot;]</span>\n<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><table><thead><tr><th>Param</th><th>Default</th><th>Effect</th></tr></thead><tbody><tr><td><code>id</code></td><td>(required)</td><td>Auction ID</td></tr><tr><td><code>components</code></td><td>all</td><td>Comma-list: <code>bid_form,countdown,history,share,buy_now,reserve</code></td></tr><tr><td><code>layout</code></td><td>two-column</td><td>two-column, stacked</td></tr></tbody></table><h2 id="countdown-timer" tabindex="-1"><a class="header-anchor" href="#countdown-timer"><span>Countdown timer</span></a></h2><div class="language-text line-numbers-mode" data-highlighter="prismjs" data-ext="text"><pre><code><span class="line">[wkafw_countdown auction=&quot;123&quot; style=&quot;large&quot;]</span>\n<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><table><thead><tr><th>Param</th><th>Default</th><th>Values</th></tr></thead><tbody><tr><td><code>auction</code></td><td>(required)</td><td>Auction ID</td></tr><tr><td><code>style</code></td><td>compact</td><td>compact, large, minimal</td></tr><tr><td><code>show_label</code></td><td>yes</td><td>yes, no</td></tr><tr><td><code>when_ended</code></td><td>hide</td><td>hide, show, redirect</td></tr></tbody></table><h2 id="bid-form-in-context" tabindex="-1"><a class="header-anchor" href="#bid-form-in-context"><span>Bid form (in-context)</span></a></h2><p>For custom auction layouts where you want to compose components yourself:</p><div class="language-text line-numbers-mode" data-highlighter="prismjs" data-ext="text"><pre><code><span class="line">[wkafw_bid_form auction=&quot;123&quot;]</span>\n<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><table><thead><tr><th>Param</th><th>Default</th><th>Effect</th></tr></thead><tbody><tr><td><code>auction</code></td><td>(required)</td><td>Auction ID</td></tr><tr><td><code>quick_bids</code></td><td>yes</td><td>Show quick-bid buttons</td></tr><tr><td><code>show_max</code></td><td>auto</td><td>Show &quot;Max bid&quot; field for proxy auctions</td></tr></tbody></table><h2 id="search-bar" tabindex="-1"><a class="header-anchor" href="#search-bar"><span>Search bar</span></a></h2><div class="language-text line-numbers-mode" data-highlighter="prismjs" data-ext="text"><pre><code><span class="line">[wkafw_search]</span>\n<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>Renders an autocomplete search input that queries auctions live (uses <code>/wp-json/wkafw/v1/search</code>).</p><table><thead><tr><th>Param</th><th>Default</th><th>Effect</th></tr></thead><tbody><tr><td><code>placeholder</code></td><td>&quot;Search auctions...&quot;</td><td>Input placeholder</td></tr><tr><td><code>limit</code></td><td>10</td><td>Max suggestions</td></tr><tr><td><code>categories</code></td><td>(none)</td><td>Restrict to categories</td></tr></tbody></table><h2 id="top-bidders-leaderboard" tabindex="-1"><a class="header-anchor" href="#top-bidders-leaderboard"><span>Top bidders / leaderboard</span></a></h2><div class="language-text line-numbers-mode" data-highlighter="prismjs" data-ext="text"><pre><code><span class="line">[wkafw_top_bidders limit=&quot;10&quot; range=&quot;all&quot;]</span>\n<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><table><thead><tr><th>Param</th><th>Default</th><th>Values</th></tr></thead><tbody><tr><td><code>limit</code></td><td>10</td><td>Number of rows</td></tr><tr><td><code>range</code></td><td>all</td><td>day, week, month, all</td></tr><tr><td><code>show_avatar</code></td><td>yes</td><td>yes, no</td></tr><tr><td><code>show_count</code></td><td>yes</td><td>yes, no</td></tr></tbody></table><h2 id="recent-winners" tabindex="-1"><a class="header-anchor" href="#recent-winners"><span>Recent winners</span></a></h2><div class="language-text line-numbers-mode" data-highlighter="prismjs" data-ext="text"><pre><code><span class="line">[wkafw_recent_winners limit=&quot;6&quot;]</span>\n<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>Shows recently-paid auctions with winner names, amounts, and &quot;won X minutes ago&quot; timestamps.</p><h2 id="customer-endpoints" tabindex="-1"><a class="header-anchor" href="#customer-endpoints"><span>Customer endpoints</span></a></h2><p>These render the same content as their respective My-Account pages — use to embed in custom dashboards:</p><div class="language-text line-numbers-mode" data-highlighter="prismjs" data-ext="text"><pre><code><span class="line">[wkafw_my_auctions tab=&quot;active&quot;]   # active / won / lost / watchlist</span>\n<span class="line">[wkafw_my_wallet]</span>\n<span class="line">[wkafw_watchlist]</span>\n<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="auction-of-the-day" tabindex="-1"><a class="header-anchor" href="#auction-of-the-day"><span>Auction of the Day</span></a></h2><div class="language-text line-numbers-mode" data-highlighter="prismjs" data-ext="text"><pre><code><span class="line">[wkafw_auction_of_day style=&quot;hero&quot;]</span>\n<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>Renders the <a href="/smart-features.html#auction-of-the-day" target="_blank" rel="noopener noreferrer">Auction of the Day</a> prominently. Style: <code>hero</code> (full-width banner) or <code>card</code> (compact).</p><h2 id="flash-auctions" tabindex="-1"><a class="header-anchor" href="#flash-auctions"><span>Flash auctions</span></a></h2><div class="language-text line-numbers-mode" data-highlighter="prismjs" data-ext="text"><pre><code><span class="line">[wkafw_flash_auctions]</span>\n<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>Grid of currently-running flash auctions with heightened urgency UI.</p><h2 id="event-landing" tabindex="-1"><a class="header-anchor" href="#event-landing"><span>Event landing</span></a></h2><div class="language-text line-numbers-mode" data-highlighter="prismjs" data-ext="text"><pre><code><span class="line">[wkafw_event_landing event_id=&quot;42&quot;]</span>\n<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>Renders an event page inline. Use to embed event listings in custom layouts.</p><h2 id="donor-wall" tabindex="-1"><a class="header-anchor" href="#donor-wall"><span>Donor wall</span></a></h2><div class="language-text line-numbers-mode" data-highlighter="prismjs" data-ext="text"><pre><code><span class="line">[wkafw_donor_wall limit=&quot;50&quot; charity_only=&quot;yes&quot;]</span>\n<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>Public donor list. Defaults to last 50 donations across all charity auctions. Set <code>charity_only=&quot;no&quot;</code> for any auction donor.</p><h2 id="compare" tabindex="-1"><a class="header-anchor" href="#compare"><span>Compare</span></a></h2><div class="language-text line-numbers-mode" data-highlighter="prismjs" data-ext="text"><pre><code><span class="line">[wkafw_compare]</span>\n<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>Renders the comparison page (up to 3 lots side-by-side).</p><h2 id="share-buttons" tabindex="-1"><a class="header-anchor" href="#share-buttons"><span>Share buttons</span></a></h2><div class="language-text line-numbers-mode" data-highlighter="prismjs" data-ext="text"><pre><code><span class="line">[wkafw_share_buttons platforms=&quot;facebook,twitter,whatsapp,linkedin&quot;]</span>\n<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>Standalone share row. Useful when you want shares on a non-auction page (e.g., &quot;share this campaign&quot;).</p><h2 id="custom-shortcodes" tabindex="-1"><a class="header-anchor" href="#custom-shortcodes"><span>Custom shortcodes</span></a></h2><p>Register your own:</p><div class="language-php line-numbers-mode" data-highlighter="prismjs" data-ext="php"><pre><code><span class="line"><span class="token function">add_shortcode</span><span class="token punctuation">(</span> <span class="token string single-quoted-string">&#39;my_auction_widget&#39;</span><span class="token punctuation">,</span> <span class="token keyword">function</span><span class="token punctuation">(</span> <span class="token variable">$atts</span> <span class="token punctuation">)</span> <span class="token punctuation">{</span></span>\n<span class="line">    <span class="token variable">$atts</span> <span class="token operator">=</span> <span class="token function">shortcode_atts</span><span class="token punctuation">(</span> <span class="token punctuation">[</span> <span class="token string single-quoted-string">&#39;category&#39;</span> <span class="token operator">=&gt;</span> <span class="token string single-quoted-string">&#39;&#39;</span><span class="token punctuation">,</span> <span class="token string single-quoted-string">&#39;limit&#39;</span> <span class="token operator">=&gt;</span> <span class="token number">5</span> <span class="token punctuation">]</span><span class="token punctuation">,</span> <span class="token variable">$atts</span> <span class="token punctuation">)</span><span class="token punctuation">;</span></span>\n<span class="line"></span>\n<span class="line">    <span class="token variable">$auctions</span> <span class="token operator">=</span> <span class="token function">wkafw_get_auctions</span><span class="token punctuation">(</span> <span class="token punctuation">[</span></span>\n<span class="line">        <span class="token string single-quoted-string">&#39;category&#39;</span> <span class="token operator">=&gt;</span> <span class="token variable">$atts</span><span class="token punctuation">[</span><span class="token string single-quoted-string">&#39;category&#39;</span><span class="token punctuation">]</span><span class="token punctuation">,</span></span>\n<span class="line">        <span class="token string single-quoted-string">&#39;limit&#39;</span>    <span class="token operator">=&gt;</span> <span class="token punctuation">(</span><span class="token keyword type-casting">int</span><span class="token punctuation">)</span> <span class="token variable">$atts</span><span class="token punctuation">[</span><span class="token string single-quoted-string">&#39;limit&#39;</span><span class="token punctuation">]</span><span class="token punctuation">,</span></span>\n<span class="line">        <span class="token string single-quoted-string">&#39;status&#39;</span>   <span class="token operator">=&gt;</span> <span class="token string single-quoted-string">&#39;active&#39;</span><span class="token punctuation">,</span></span>\n<span class="line">    <span class="token punctuation">]</span> <span class="token punctuation">)</span><span class="token punctuation">;</span></span>\n<span class="line"></span>\n<span class="line">    <span class="token function">ob_start</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>\n<span class="line">    <span class="token keyword">foreach</span> <span class="token punctuation">(</span> <span class="token variable">$auctions</span> <span class="token keyword">as</span> <span class="token variable">$auction</span> <span class="token punctuation">)</span> <span class="token punctuation">{</span></span>\n<span class="line">        <span class="token comment">// ... your output</span></span>\n<span class="line">    <span class="token punctuation">}</span></span>\n<span class="line">    <span class="token keyword">return</span> <span class="token function">ob_get_clean</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>\n<span class="line"><span class="token punctuation">}</span> <span class="token punctuation">)</span><span class="token punctuation">;</span></span>\n<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="performance" tabindex="-1"><a class="header-anchor" href="#performance"><span>Performance</span></a></h2><p>Shortcodes cache their query results:</p><ul><li>60-second TTL for active-auction queries</li><li>Cached per-shortcode-attribute hash</li><li>Bust on bid placement (cache invalidation tied to <code>wkafw_bid_placed</code> hook)</li></ul><p>For very-high-traffic pages with many shortcodes, ensure object cache (Redis / Memcached) is enabled.</p><h2 id="common-questions" tabindex="-1"><a class="header-anchor" href="#common-questions"><span>Common questions</span></a></h2><p><strong>&quot;Can I use these in widgets?&quot;</strong></p><p>Yes — shortcodes work in WP Text widgets, Custom HTML widgets, Elementor&#39;s &quot;Shortcode&quot; widget, and similar.</p><p><strong>&quot;How do I get a list of currently-active auctions in PHP?&quot;</strong></p><p>Use <code>wkafw_get_auctions()</code> directly:</p><div class="language-php line-numbers-mode" data-highlighter="prismjs" data-ext="php"><pre><code><span class="line"><span class="token variable">$auctions</span> <span class="token operator">=</span> <span class="token function">wkafw_get_auctions</span><span class="token punctuation">(</span> <span class="token punctuation">[</span></span>\n<span class="line">    <span class="token string single-quoted-string">&#39;status&#39;</span> <span class="token operator">=&gt;</span> <span class="token string single-quoted-string">&#39;active&#39;</span><span class="token punctuation">,</span></span>\n<span class="line">    <span class="token string single-quoted-string">&#39;limit&#39;</span>  <span class="token operator">=&gt;</span> <span class="token number">10</span><span class="token punctuation">,</span></span>\n<span class="line">    <span class="token string single-quoted-string">&#39;sort&#39;</span>   <span class="token operator">=&gt;</span> <span class="token string single-quoted-string">&#39;end_date&#39;</span><span class="token punctuation">,</span></span>\n<span class="line">    <span class="token string single-quoted-string">&#39;order&#39;</span>  <span class="token operator">=&gt;</span> <span class="token string single-quoted-string">&#39;ASC&#39;</span><span class="token punctuation">,</span></span>\n<span class="line"><span class="token punctuation">]</span> <span class="token punctuation">)</span><span class="token punctuation">;</span></span>\n<span class="line"><span class="token keyword">foreach</span> <span class="token punctuation">(</span> <span class="token variable">$auctions</span> <span class="token keyword">as</span> <span class="token variable">$auction</span> <span class="token punctuation">)</span> <span class="token punctuation">{</span></span>\n<span class="line">    <span class="token keyword">echo</span> <span class="token variable">$auction</span><span class="token operator">-&gt;</span><span class="token property">title</span> <span class="token operator">.</span> <span class="token string single-quoted-string">&#39; — $&#39;</span> <span class="token operator">.</span> <span class="token variable">$auction</span><span class="token operator">-&gt;</span><span class="token property">current_price</span><span class="token punctuation">;</span></span>\n<span class="line"><span class="token punctuation">}</span></span>\n<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>&quot;Why does <code>[wkafw_bid_form]</code> show &#39;Auction not found&#39;?&quot;</strong></p><p>The shortcode requires <code>auction</code> attribute with a valid auction ID. Ensure you&#39;re passing it correctly: <code>[wkafw_bid_form auction=&quot;123&quot;]</code>.</p>',64)])])}]]),o=JSON.parse('{"path":"/shortcodes.html","title":"Shortcodes","lang":"en-US","frontmatter":{},"headers":[{"level":2,"title":"Quick reference","slug":"quick-reference","link":"#quick-reference","children":[]},{"level":2,"title":"Auction list grid","slug":"auction-list-grid","link":"#auction-list-grid","children":[]},{"level":2,"title":"Single auction","slug":"single-auction","link":"#single-auction","children":[]},{"level":2,"title":"Countdown timer","slug":"countdown-timer","link":"#countdown-timer","children":[]},{"level":2,"title":"Bid form (in-context)","slug":"bid-form-in-context","link":"#bid-form-in-context","children":[]},{"level":2,"title":"Search bar","slug":"search-bar","link":"#search-bar","children":[]},{"level":2,"title":"Top bidders / leaderboard","slug":"top-bidders-leaderboard","link":"#top-bidders-leaderboard","children":[]},{"level":2,"title":"Recent winners","slug":"recent-winners","link":"#recent-winners","children":[]},{"level":2,"title":"Customer endpoints","slug":"customer-endpoints","link":"#customer-endpoints","children":[]},{"level":2,"title":"Auction of the Day","slug":"auction-of-the-day","link":"#auction-of-the-day","children":[]},{"level":2,"title":"Flash auctions","slug":"flash-auctions","link":"#flash-auctions","children":[]},{"level":2,"title":"Event landing","slug":"event-landing","link":"#event-landing","children":[]},{"level":2,"title":"Donor wall","slug":"donor-wall","link":"#donor-wall","children":[]},{"level":2,"title":"Compare","slug":"compare","link":"#compare","children":[]},{"level":2,"title":"Share buttons","slug":"share-buttons","link":"#share-buttons","children":[]},{"level":2,"title":"Custom shortcodes","slug":"custom-shortcodes","link":"#custom-shortcodes","children":[]},{"level":2,"title":"Performance","slug":"performance","link":"#performance","children":[]},{"level":2,"title":"Common questions","slug":"common-questions","link":"#common-questions","children":[]}],"git":{},"filePathRelative":"shortcodes.md"}')}}]);